scwin.f_openPopUp = async function (flag, pCode, check, isCdYn) {
  let param;
  let selectID;
  let row = ds_slipcontents.getRowPosition();
  let costClsCd;
  switch (flag) {
    case '1':
      // 부서 
      param = ed_slipDt.getValue().trim() + ",," + scwin.vCoCd + "," + scwin.vCoClsCd;
      udc_slipAcctDeptCd.setSelectId("retrieveAcctDeptCdInfo3");
      udc_slipAcctDeptCd.cfCommonPopUp(scwin.udc_slipAcctDeptCd_callbackfunc, pCode, '', check, null, null, null, null, param, null, null, null, null);
      //f_resultPopEd(ed_slipAcctDeptCd,txt_slipAcctDeptNm,rtnList);

      break;
    case '2':
      // 계정조회
      if (ed_acctDeptCd.getValue() == "") {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, Array("귀속부서"));
        ed_acctDeptCd.focus();
        return;
      }

      // 비용구분 : 01^원가,02^판관비,03^원가+판관비,04^판관비제외,05^원가제외
      let tempCostClsCd = ds_slipcontents.getCellData(row, "tempCostClsCd");
      //if(scwin.txt_tempCostClsCd == "03") {
      if (tempCostClsCd == "03") {
        //scwin.txt_costClsCd = "04";		// 전체조회
        ds_slipcontents.setCellData(row, "costClsCd", "04");
      } else if (tempCostClsCd == "01") {
        //scwin.txt_costClsCd.value = "05";		// 원가
        ds_slipcontents.setCellData(row, "costClsCd", "05");
      } else if (tempCostClsCd == "02") {
        //scwin.txt_costClsCd.value = "06";		// 판관비
        ds_slipcontents.setCellData(row, "costClsCd", "06");
      } else {
        //scwin.txt_costClsCd.value = "";
        ds_slipcontents.setCellData(row, "costClsCd", "");
      }

      // 계정코드가 
      let where = "";
      let temp = "T,,";
      //동부익스프레스, 자회사 구분으로 계정 팝업창 틀림 
      costClsCd = ds_slipcontents.getCellData(row, "costClsCd");
      if (scwin.isSubCompany == false) {
        where = ed_slipDt.getValue().trim() + "," + costClsCd + ",Y";
        udc_acctCd.setSelectId("retrieveTransferAcctCdInfo");
        udc_acctCd.cfCommonPopUp(scwin.udc_acctCd_callbackfunc, pCode, '', check, null, null, null, null, where, null, null, null, null);
      } else {
        //where = "," +","+ scwin.txt_costClsCd;
        where = "," + "," + costClsCd;
        udc_acctCd.setSelectId("retrieveAcctCdInfo");
        udc_acctCd.cfCommonPopUp(scwin.udc_acctCd_callbackfunc, pCode, '', check, null, null, null, null, temp, null, null, null, null);
      }
      break;
    case '3':
      // 부서		
      param = ed_slipDt.getValue().trim() + ",," + scwin.vCoCd + "," + scwin.vCoClsCd;
      udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callbackfunc, pCode, '', check, null, null, null, null, param, null, null, null, null);
      break;

    // 거래처	    
    case '4':
      param = scwin.vCoCd;
      // 20110704 거래처여부 예외처리 
      // 예외적 상황으로, 계정이 가지급 에 해당하는 경우는 일반의 경우와 팝업을 분리한다.
      // 가지급 경우( 계정번호:명칭 1110530:단기대여금-업무가지급금(일반),1110531:단기대여금-업무가지급금(급여), 1110540:단기대여금-매표가지급금 )
      // 입력한 사원번호를 기준으로 거래처를 검색한다. 
      if (ed_acctCd.getValue() == '1110530' || ed_acctCd.getValue() == '1110531') {
        if (ed_mgntEmpNo.getValue() == "" || ed_mgntEmpNo.getValue() == null) {
          await $c.win.alert($p, "계정이 가지급인 경우, 사원번호는 필수 항목입니다. ");
          return;
        } else {
          udc_mgntClntNo.setSelectId("retrieveMgntEmpNoList");
          udc_mgntClntNo.cfCommonPopUp(scwin.udc_mgntClntNo_callbackfunc, pCode, '', check, null, null, null, null, null, null, null, null, null);
        }
      } else {
        udc_mgntClntNo.setSelectId("retrieveClntEmpNoList");
        udc_mgntClntNo.cfCommonPopUp(scwin.udc_mgntClntNo_callbackfunc, pCode, '', check, null, null, null, null, param, null, null, null, null);
      }
      break;
    case '5':
      // 사번
      param = '';
      if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
        // 자회사 회계 시스템
        param = scwin.txtCoCd + "," + scwin.txtCoClsCd;
      }
      udc_mgntEmpNo.cfCommonPopUp(scwin.udc_mgntEmpNo_callbackfunc, pCode, '', check, null, null, null, null, param, null, null, null, null);
      //f_resultPopEd(ed_mgntEmpNo,txt_mgntEmpNm,rtnList);
      break;
    case '6':
      //지점코드 조회
      var returnObject = RcfBranchAcctDeptPop(ed_branchCd, ed_branchNm, isCdYn, '1', '전체', 'D', '');
      if (returnObject != null) {
        ed_acctDeptCd.setValue(returnObject.shtTermAcctDeptCd);
        ed_acctDeptNm.setValue(returnObject.shtTermAcctDeptNm);
        ed_branchCd.setValue(returnObject.branchCd);
        ed_branchCd.options.hidVal = returnObject.branchCd;
        ed_branchNm.setValue(returnObject.branchNm);
        scwin.f_checkPopEd(ed_acctDeptCd, ed_acctDeptNm, '3');
        ed_acctDeptCd.options.hidVal = returnObject.shtTermAcctDeptCd;
      } else {
        ed_branchCd.setValue("");
        ed_branchCd.options.hidVal("");
        ed_branchNm.setValue("");
      }
      break;
    case '7':
      //매출입항목코드 조회
      if (ed_acctDeptCd.getValue() == "") {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, Array("귀속부서"));
        ed_acctDeptCd.focus();
        return;
      }
      pCode = "";
      pWhere = "1," + ed_slipDt.getValue().trim() + "," + ed_slipAcctDeptCd.getValue().trim() + ",";
      pTitle = "매입항목코드,매입항목명";
      pWindowTitle = "매입항목코드조회,매입항목코드,매입항목명";
      udc_pchsItemCd.cfCommonPopUp(scwin.udc_pchsItemCd_callbackfunc // XML상의 SELECT ID	
      , ed_pchsItemCd.getValue().trim() // 화면에서의 ??? Code Element의	Value
      , ed_pchsItemNm.getValue() // 화면에서의 ??? Name Element의	Value
      , check // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
      , '2' // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
      , pTitle // Title순서	
      , '150,210' // 보여주는 각 컬럼들의 폭	
      , null // 컬럼중에서 숨기는	컬럼 지정	
      , pWhere // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
      , '440' // POP-UP뛰을때 원도우의	사용자 정의	폭
      , '500' // POP-UP뛰을때 우도우의	사용자 정의	높이	
      , null // 윈도우 위치 Y좌표	
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부	("F")
      , 'F' // 전체검색허용여부	("F")
      , pWindowTitle // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
      );
      break;
    case '8':
      // 사업자번호
      param = '';
      selectID = 'retrieveCrnInfo';
      udc_crn.setSelectId(selectID);
      udc_crn.cfCommonPopUp(scwin.udc_crn_callbackfunc, pCode, '', check, null, null, null, null, param, null, null, null, null);
      break;
    case '9':
      // 상대계정조회
      // 선급비용 처리분에 선급비용-일반 계정이 추가됨으로 인한 상대계정 입력필드 추가
      // 비용구분 : 01^원가,02^판관비,03^원가+판관비,04^판관비제외,05^원가제외
      let tempOpntAcctCostClsCd = ds_slipcontents.getCellData(row, "tempOpntAcctCostClsCd");
      if (tempOpntAcctCostClsCd == "03") {
        //scwin.txt_opntAcctCostClsCd = "04";		// 전체조회
        ds_slipcontents.setCellData(row, "opntAcctCostClsCd", "04");
      } else if (tempOpntAcctCostClsCd == "01") {
        scwin.txt_opntAcctCostClsCd = "05"; // 원가
        ds_slipcontents.setCellData(row, "opntAcctCostClsCd", "05");
      } else if (tempOpntAcctCostClsCd == "02") {
        scwin.txt_opntAcctCostClsCd = "06"; // 판관비
        ds_slipcontents.setCellData(row, "opntAcctCostClsCd", "06");
      } else {
        scwin.txt_opntAcctCostClsCd = "";
        ds_slipcontents.setCellData(row, "opntAcctCostClsCd", "");
      }

      // 계정코드가 
      where = "";
      costClsCd = ds_slipcontents.getCellData(row, "costClsCd");
      //동부익스프레스, 자회사 구분으로 계정 팝업창 틀림 
      if (scwin.isSubCompany == false) {
        where = ed_slipDt.getValue().trim() + "," + costClsCd + ",Y";
        udc_opntAcctCd.setSelectId("retrieveTransferAcctCdInfo");
        udc_opntAcctCd.cfCommonPopUp(scwin.udc_opntAcctCd_callbackfunc, ed_acctCd.getValue().trim(), ed_acctNm.value, check, null, null, null, null, where, null, null, null, null);
      } else {
        where = ed_slipDt.getValue().trim() + "," + costClsCd;
        udc_opntAcctCd.setSelectId("retrieveTransferAcctCdInfo2");
        udc_opntAcctCd.cfCommonPopUp(scwin.udc_opntAcctCd_callbackfunc, ed_acctCd.getValue().trim(), ed_acctNm.value, check, null, null, null, null, where, null, null, null, null);
      }
      break;
    default:
      break;
  }
};

