scwin.udc_acctCd_callbackfunc = async function (rtnList) {
  let row = ds_slipcontents.getRowPosition();
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      return;
    }

    //ed_acctCd.setValue( rtnList[0]);	//계정코드
    //ed_acctNm.setValue( rtnList[1] );	//계정명
    //ed_acctCd.options.hidVal = rtnList[0];  // 히든값
    ds_slipcontents.setCellData(row, "acctCd", rtnList[0]);
    ds_slipcontents.setCellData(row, "acctNm", rtnList[1]);
    ds_slipcontents.setCellData(row, "hid_acctCd", rtnList[0]);
    scwin.f_AcctCdCheck();
    if (ACConstants.CO_CD_DONGBU == scwin.vCoCd) {
      // 결과값 가지고 왔을때 원)세금과공과-과징금(4203417), 판)세금과공과-과징금(5001917) 계정일 경우
      // 잡손실(6120220)계정으로 작성해 주시기 바랍니다. 라는 메시지 출력해 준다.
      // 본사만
      if (ed_acctCd.getValue() == '4203417') {
        await $c.win.alert($p, "원)세금과공과-과징금(4203417) 계정을 \n\n잡손실(6120220)계정으로 작성해 주시기 바랍니다.");
        //ed_acctCd.setValue("");
        //ed_acctNm.setValue("");
        ds_slipcontents.setCellData(row, "acctCd", "");
        ds_slipcontents.setCellData(row, "acctNm", "");
        return;
      } else if (ed_acctCd.getValue() == '5001917') {
        await $c.win.alert($p, "판)세금과공과-과징금(5001917) 계정을 \n\n잡손실(6120220)계정으로 작성해 주시기 바랍니다.");
        //ed_acctCd.setValue("");
        //ed_acctNm.setValue("");
        ds_slipcontents.setCellData(row, "acctCd", "");
        ds_slipcontents.setCellData(row, "acctNm", "");
        return;
      }
    }

    //---------------------------------------------------------
    //  채권채무선수금정리를 위한 구분값 적용
    //---------------------------------------------------------
    ed_acctClsCd.setValue(rtnList[2]); // 계정구분코드
    ds_slipcontents.setCellData(row, "acctClsCd", rtnList[2]);
    scwin.f_checkSettle("", "", row); //정리구분셋팅

    // 계정셋팅
    scwin.f_AcctCd(rtnList[4], rtnList[5], rtnList[6], rtnList[7], rtnList[8], rtnList[9], rtnList[10], row);
    if (lc_drcrClsCd.getValue() == "C" && ed_acctCd.getValue() == "1110530") {
      if (scwin.isSubCompany == true) {
        //자회사 정산방법 선택 불가
        lc_adjmClsCd.setValue(-1); //정산방법
        $c.gus.cfDisableObjects($p, [btn_adjmClsCd]);
      } else {
        lc_adjmClsCd.setValue(ACConstants.ADJM_MTHDCD_SUSPAY);
        $c.gus.cfEnableObjects($p, [btn_adjmClsCd]);
      }
    } else {
      if (scwin.isSubCompany == true) {
        //자회사 정산방법 선택 불가
        lc_adjmClsCd.setValue(-1); //정산방법 
        $c.gus.cfDisableObjects($p, [btn_adjmClsCd]);
      } else {
        lc_adjmClsCd.setValue(0);
        $c.gus.cfDisableObjects($p, [btn_adjmClsCd]);
      }
    }
  } else {
    //ed_acctCd.setValue("");
    //ed_acctNm.setValue("");
    //ed_mgntNm.setValue("");
    //ed_acctCd.options.hidVal ="";
    //scwin.txt_payAcctCd ="";

    ds_slipcontents.setCellData(row, "acctCd", "");
    ds_slipcontents.setCellData(row, "acctNm", "");
    ds_slipcontents.setCellData(row, "mgntNm", "");
    ds_slipcontents.setCellData(row, "hid_acctCd", "");
    ds_slipcontents.setCellData(row, "payAcctCd", "");
  }

  // 부가세대급금이 대변  계정, 부가세예수금이 차변계정  입력시는 사업자번호, 부가세관리부서등 부가세관련 데이터 입력가능
  if (ed_acctCd.getValue() == "1111210" && lc_drcrClsCd.getValue() == "D" || ed_acctCd.getValue() == "2100710" && lc_drcrClsCd.getValue() == "C") {
    $c.gus.cfEnableObjects($p, [ed_taxInvcDt, lc_evidClsCd, lc_deductClsCd, ed_vatDeclarAcctDeptCd, ed_crn, ed_spplyAmt, ed_vatAmt, btn_crn]);
    //img_taxInvcDt, img_taxInvcDt, 달력아이콘은 따로 제어가 되는지 리서치가 필요해서 제외

    ds_slipcontents.setCellData(ds_slipcontents.getRowPosition(), "taxinvcDt", ed_slipDt.getValue());
  } else {
    $c.gus.cfDisableObjects($p, [ed_taxInvcDt, lc_evidClsCd, lc_deductClsCd, ed_vatDeclarAcctDeptCd, ed_crn, ed_spplyAmt, ed_vatAmt, btn_crn]);
    //img_taxInvcDt
  }

  // 계정이 선급비용-일반일 경우 상대계정필드 활성화
  if (ed_acctCd.getValue() == ACConstants.ACCTCD_PREPAY_COST) {
    $c.gus.cfEnableObjects($p, [ed_opntAcctCd, ed_opntAcctNm, btn_opntAcctCd]);
  } else {
    ed_opntAcctCd.setValue("");
    ed_opntAcctNm.setValue("");
    ed_opntAcctCd.options.hidVal = "";
    $c.gus.cfDisableObjects($p, [ed_opntAcctCd, ed_opntAcctNm, btn_opntAcctCd]);
  }
};
