//  가지급금,선급금 정리화면_팝업 이미지 클릭함수 
//-------------------------------------------------------------------------  
scwin.f_Prepay = function () {
  if (lc_crcCd.getValue() == "KRW") {
    // 통화코드가 KRW면 
    if (!$c.gus.cfValidate($p, [ed_slipDt, ed_acctDeptCd, ed_amt]))
      // 작성일자와, 귀속부서, 금액 값유무 확인 
      return false;
  } else {
    // 그외통화코드는
    if (!$c.gus.cfValidate($p, [ed_slipDt, ed_acctDeptCd, ed_amtFcrc]))
      // 작성일자와, 귀속부서, 외화금액 값 유무 확인 
      return false;
  }
  var sum = 0; // 금액(한화/외화)

  if (lc_crcCd.getValue() == ACConstants.KOREA_WON) {
    // 통화코드가 한화면 
    sum = Number(ed_amt.getValue().trim()); // 금액입력
  } else {
    // 그외면
    sum = Number(ed_amtFcrc.getValue().trim()); // 외화입력 
  }

  // 가지급금선급금입금 정리 팝업용 파라미터객체 생성 
  //var valueObject = new Object();
  //valueObject.prov       = ds_prov;                          // 
  //valueObject.provHeader = ds_provHeader;                    // 
  //valueObject.txtrltSeq  = ds_slipcontents.getCellData(ds_slipcontents.getRowPosition(),"rltSeq"); // 정산순번
  //valueObject.adjmClsCd  = lc_adjmClsCd.getValue().trim();   // 정산방법
  //valueObject.sum        = sum;                              // 정산대상금액
  //valueObject.crcCd      = lc_crcCd.getValue();              // 통화코드

  var acctDeptCd;
  var acctDeptNm;
  for (j = 0; j < ds_provHeader.getRowCount(); j++) {
    if (ds_slipcontents.getCellData(ds_slipcontents.getRowPosition(), "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
      if (ds_provHeader.getCellData(j, "reqAcctDeptCd") != "") {
        //valueObject.acctDeptCd = ds_provHeader.getCellData(j,"reqAcctDeptCd") // 신청부서코드
        //valueObject.acctDeptNm = ds_provHeader.getCellData(j,"reqAcctDeptNm") // 신청부서명 
        acctDeptCd = ds_provHeader.getCellData(j, "reqAcctDeptCd");
        acctDeptNm = ds_provHeader.getCellData(j, "reqAcctDeptNm");
      }
    }
  }
  if (typeof acctDeptCd == "undefined" || acctDeptCd == "") {
    acctDeptCd = ed_acctDeptCd.getValue().trim();
    acctDeptNm = ed_acctDeptNm.getValue().trim();
  }

  // 가지급금선급금입금 팝업설정 
  //var style       = "center:yes; dialogwidth:1000px; dialogheight:520px; scroll:no; resizable:no; status:yes;";
  //var strPath     = "fi_201_02_02b.xml?compare=1&flag=Y&slipDt="+ed_slipDt.getValue().trim();
  //var returnValue = window.showModalDialog(strPath, valueObject ,style ) ;

  var win_url = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.xml";
  let opts = {
    id: "smpPop",
    popupName: "가지급금입금",
    modal: true,
    type: "browserPopup",
    width: 1400,
    height: 760,
    title: "가지급금입금"
  };
  let data = {
    compare: 1,
    flag: "Y",
    slipDt: ed_slipDt.getValue().trim(),
    prov: ds_prov,
    provHeader: ds_provHeader,
    txtrltSeq: ds_slipcontents.getCellData(ds_slipcontents.getRowPosition(), "rltSeq"),
    adjmClsCd: lc_adjmClsCd.getValue().trim(),
    sum: sum,
    crcCd: lc_crcCd.getValue(),
    acctDeptCd: acctDeptCd,
    acctDeptNm: acctDeptNm
  };
  let returnValue = $c.win.openPopup($p, win_url, opts, data);

  //결좌데이터 정리   	
  if (returnValue != null) {
    //ds_prov.ImportData(returnValue.prov);
    ds_prov.setRowPosition(ds_prov.getRowCount());
    ds_prov.setRowData(ds_prov.getRowPosition(), returnValue.prov, false);

    //ds_provHeader.ImportData(returnValue.provHeader);
    ds_provHeader.setRowPosition(ds_provHeader.getRowCount());
    ds_provHeader.setRowData(ds_provHeader.getRowPosition(), returnValue.provHeader, false);

    //ds_prov.SortExpr= "+rltSeq +slipNo";
    //ds_prov.Sort();
    let options = {};
    options.sortIndex = "rltSeq slipNo";
    options.sortOrder = "1 1";
    ds_prov.multisort(options);

    // 중복된것 삭제
    for (i = 0; i < ds_prov.getRowCount() - 1; i++) {
      for (j = i + 1; j < ds_prov.getRowCount(); j++) {
        if (ds_prov.getCellData(i, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
          if (ds_prov.getCellData(i, "slipNo") == ds_prov.getCellData(j, "slipNo")) {
            ds_prov.removeRow(i);
            break;
          }
        }
      }
    } // for end

    for (i = 0; i < ds_provHeader.getRowCount() - 1; i++) {
      for (j = i + 1; j < ds_provHeader.getRowCount(); j++) {
        if (ds_provHeader.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
          ds_provHeader.removeRow(i);
          break;
        }
      }
    } // for end
  }
};

