//------------------------------------------------------------------------
// 계정코드, 차/대변을 가지고 채권채무선수금 정리대상 계정인지 체크하는 함수
//------------------------------------------------------------------------
scwin.f_checkSettle = async function (r_acctCd, r_drcrClsCd, row) {
  if (r_acctCd == null) r_acctCd = "";
  if (r_drcrClsCd == null) r_drcrClsCd = "";
  //ds_settleAccount.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
  //+ "&queryId=retrieveSettleInfo&param1="+r_acctCd
  //+ "&param2="+r_drcrClsCd;
  //ds_settleAccount.Reset();
  let strAction = "/cm.zz.RetrieveCommonPopupCMD.do?X-UIClient=G40/D1,1,2,68&sysCd=CommonEBC" + "&queryId=retrieveSettleInfo&param1=" + r_acctCd + "&param2=" + r_drcrClsCd;
  //sbm_settleAccount;
  sbm_settleAccount.action = strAction;
  let result = await $c.sbm.execute($p, sbm_settleAccount);
  let responseJSON = result.responseJSON;
  if (responseJSON.resultDataSet[0].Code == '0') {
    let resultJSON = responseJSON.GAUCE;
    ds_settleAccount.setJSON(resultJSON); // 증빙종류 세팅
  }
  if (!ds_settleAccount || ds_settleAccount.getDataLength() === 0) {
    ed_method.setValue("");
    ds_slipcontents.setCellData(row, "settleClsCd", "0");
    return false;
  }
  if (ds_settleAccount.getCellData(0, "col1") == "N/A" || typeof ds_settleAccount.getCellData(0, "col1") == "undefined") {
    //alert("정리대상 아님!!");
    //ed_settleClsCd.setValue("0");
    ed_method.setValue("");
    ds_slipcontents.setCellData(row, "settleClsCd", "0"); //정리구분 셋팅
    return false;
  } else {
    //alert("정리대상임!!!!!");
    //ed_settleClsCd.setValue ( ds_settleAccount.getCellData(0,"col3") );
    ed_method.value = "채권정리";
    ds_slipcontents.setCellData(row, "settleClsCd", ds_settleAccount.getCellData(0, "col3")); //정리구분 셋팅
    return true;
  }
};

//-------------------------------------------------------------------------
//  계정조회시화면셋팅
//  r_mgntCd - 관리번호
//  r_termMgntYn - 기간관리여부
//  r_clntMgntYn - 거래처여부
//  r_empMgntYn - 사원관리여부
//  r_mgntNm - 관리사원명
//  r_dtMgntYn - 일자관리여부
//-------------------------------------------------------------------------
scwin.f_AcctCd = async function (r_mgntCd, r_clntMgntYn, r_termMgntYn, r_empMgntYn, r_mgntNm, r_dtMgntYn, r_payAcctCd, row) {
  //scwin.txt_termMgntYn = r_termMgntYn;
  //scwin.txt_clntMgntYn = r_clntMgntYn;
  //scwin.txt_empMgntYn  = r_empMgntYn;
  //scwin.txt_dtMgntYn   = r_dtMgntYn;
  //scwin.txt_payAcctCd  = r_payAcctCd;

  ds_slipcontents.setCellData(row, "termMgntYn", r_termMgntYn);
  ds_slipcontents.setCellData(row, "clntMgntYn", r_clntMgntYn);
  ds_slipcontents.setCellData(row, "empMgntYn", r_empMgntYn);
  ds_slipcontents.setCellData(row, "dtMgntYn", r_dtMgntYn);
  if (r_payAcctCd == undefined) {
    // ASIS에서 undefin으로 세팅이 됨
    ds_slipcontents.setCellData(row, "payAcctCd", "undefin");
  } else {
    ds_slipcontents.setCellData(row, "payAcctCd", r_payAcctCd);
  }
  let acctCd = ds_slipcontents.getCellData(row, "acctCd");
  if (r_mgntCd != "" && r_mgntCd != "0" || r_mgntNm != "") {
    //txt_mgntNo.value = "";
    ed_mgntNm.setValue(r_mgntNm);
    ds_slipcontents.setCellData(row, "mgntNm", r_mgntNm);
    $c.gus.cfEnableObj($p, ed_mgntNo, true);
    $c.gus.cfEnableObj($p, ed_mgntNm, false);

    //채권채무정리를 위한 추가 2013.10.24
    if ((await scwin.f_checkSettle(acctCd, ds_slipcontents.getCellData(row, "drcrClsCd"), row)) && acctCd != "") {
      $c.gus.cfEnableObjects($p, [btn_setlMthd]);
      $c.gus.cfDisableObjects($p, [ed_refNo, ed_mgntNm, ed_method, ed_settleClsCd, ed_mgntNo]);
    } else {
      //정리대상이 아닌경우 popup에서 내려받은값 초기화
      if (ds_slipcontents.getCellData(row, "settleClsCd") != "0" || ds_slipcontents.getCellData(row, "settleClsCd") != "") {
        //alert("f_AcctCd_초기화 진행!!!");
        scwin.f_initSettle(ds_slipcontents.getRowPosition(), '2');
      }
      $c.gus.cfEnableObj($p, ed_mgntNo, true);
      $c.gus.cfDisableObjects($p, [ed_mgntNm, ed_refNo, ed_method, btn_setlMthd, ed_settleClsCd]);
    }
  } else {
    //ed_mgntNo.setValue("");
    //ed_mgntNm.setValue("");	
    ds_slipcontents.setCellData(row, "mgntNo", "");
    ds_slipcontents.setCellData(row, "mgntNm", "");
    $c.gus.cfEnableObj($p, ed_mgntNo, false);
    $c.gus.cfEnableObj($p, ed_mgntNm, false);
    //채권채무정리를 위한 추가 2013.10.24
    $c.gus.cfDisableObjects($p, [ed_refNo, ed_method, btn_setlMthd, ed_settleClsCd]);
  }

  // 거래처여부
  if (r_clntMgntYn == "1") {
    //ed_mgntClntNo.validExp="거래처:yes:format=000000";
    ed_mgntClntNo.options.length = 6;
    $c.gus.cfEnableObjects($p, [ed_mgntClntNo, btn_mgntClntNo]);
  }
  // 20110704 거래처여부 예외처리 by kimseok 
  // 예외적 상황으로, 계정이 가지급 에 해당하는 경우는 거래처 항목을 활성화 
  // 가지급 경우( 계정번호:명칭 1110530:단기대여금-업무가지급금(일반),1110531:단기대여금-업무가지급금(급여), 1110540:단기대여금-매표가지급금 )
  else if (acctCd == '1110530' || acctCd == '1110531' || acctCd == '1110540') {
    $c.gus.cfEnableObjects($p, [ed_mgntClntNo, btn_mgntClntNo, ed_mgntEmpNo]);
  } else {
    $c.gus.cfDisableObjects($p, [ed_mgntClntNo, btn_mgntClntNo]);
  }

  // 사원관리여부
  if (r_empMgntYn == "1") {
    //ed_mgntEmpNo.validExp="사원번호:yes:format=000000";
    ed_mgntEmpNo.options.length = 6;
    $c.gus.cfEnableObjects($p, [ed_mgntEmpNo, btn_mgntEmpNo]);
  }
  // 20110704 거래처여부 예외처리 by kimseok 
  // 예외적 상황으로, 계정이 가지급 에 해당하는 경우는 사원번호  항목을 활성화 
  // 가지급 경우( 계정번호:명칭 1110530:단기대여금-업무가지급금(일반),1110531:단기대여금-업무가지급금(급여), 1110540:단기대여금-매표가지급금 )
  else if (acctCd == '1110530' || acctCd == '1110531' || acctCd == '1110540') {
    $c.gus.cfEnableObjects($p, [ed_mgntEmpNo, btn_mgntEmpNo]);
  } else {
    //ed_mgntEmpNo.setValue("");
    //ed_mgntEmpNm.setValue("");
    //ed_mgntEmpNo.validExp="사원번호:no:format=000000";

    ds_slipcontents.setCellData(row, "mgntEmpNo", "");
    ds_slipcontents.setCellData(row, "mgntEmpNm", "");
    ed_mgntEmpNo.options.length = "";
    $c.gus.cfDisableObjects($p, [ed_mgntEmpNo, btn_mgntEmpNo]);
  }
  // 일자관리여부  	
  //alert(parseInt(r_dtMgntYn));
  if (parseInt(r_dtMgntYn) == "1") {
    //ed_mgntDt.validExp="관리일자:yes:date=YYYYMMDD";
    $c.gus.cfEnableObjects($p, [ed_mgntDt]);
  } else {
    //ed_mgntDt.setValue("");
    //	ed_mgntDt.validExp="관리일자:no:date=YYYYMMDD";
    $c.gus.cfDisableObjects($p, [ed_mgntDt]);
  }
  if (acctCd == ACConstants.ACCTCD_TRUST_SELL && ds_slipcontents.getCellData(row, "drcrClsCd") == ACConstants.DEBIT) {
    $c.gus.cfEnableObjects($p, [chb_recvProcYn]);
    //chb_recvProcYn.checked=true;
    //chb_recvProcYn.setValue(1);

    ds_slipcontents.setCellData(row, "recvProcYn", "1");
  } else {
    $c.gus.cfDisableObjects($p, [chb_recvProcYn]);
  }

  // 지급계정셋팅
  scwin.f_PayYn(row);
};

