scwin.f_SetlMthd = async function () {
  // 채권,채무,선수금 정리 팝업용 파라미터객체 생성 
  let data = {
    "acctDeptCd": ed_acctDeptCd.getValue().trim(),
    "acctDeptNm": ed_acctDeptNm.getValue(),
    "mgntClntNo": ed_mgntClntNo.getValue().trim(),
    // 거래처코드
    "mgntClntNm": ed_mgntClntNm.getValue(),
    "acctCd": ed_acctCd.getValue().trim(),
    // 계정코드
    "acctNm": ed_acctNm.getValue(),
    "settleClsCd": ed_settleClsCd.getValue(),
    "crcCd": lc_crcCd.getValue(),
    // 통화코드
    "flag": "Y"
  };
  let ret;
  ret = $c.gus.cfValidate($p, [ed_acctDeptCd, ed_acctCd, ed_mgntClntNo]);
  if (!ret) {
    return false;
  }

  //var style       = "center:yes; dialogwidth:1000px; dialogheight:520px; scroll:no; resizable:no; status:yes;";
  //var strPath     = "fi_201_03_04p.jsp?settleclscd="+ed_settleClsCd.value+"&flag=Y";
  //var returnValue = window.showModalDialog(strPath, valueObject ,style ) ;

  sURL = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_03_04p.xml";
  const options = {
    id: "fi_201_03_04p",
    type: "popup",
    modal: true,
    popupName: "채권채무선수금조회",
    width: 1180,
    height: 750
  };
  let returnValue = await $c.win.openPopup($p, sURL, options, data);
  if (returnValue != null && returnValue.stlOutbrNo != "N/A") {
    let rp = ds_slipcontents.getRowPosition();
    ds_slipcontents.setCellData(rp, "stlOutbrDt", returnValue.stlOutbrDt);
    ds_slipcontents.setCellData(rp, "stlSlipNo", returnValue.stlSlipNo);
    ds_slipcontents.setCellData(rp, "stlOutbrNo", returnValue.stlOutbrNo);
    ds_slipcontents.setCellData(rp, "stlClntNo", returnValue.stlClntNo);
    ds_slipcontents.setCellData(rp, "stlClntNm", returnValue.stlClntNm);
    ds_slipcontents.setCellData(rp, "stlAcctDeptCd", returnValue.stlAcctDeptCd);
    ds_slipcontents.setCellData(rp, "stlAcctDeptNm", returnValue.stlAcctDeptNm);
    ds_slipcontents.setCellData(rp, "stlAcctCd", returnValue.stlAcctCd);
    ds_slipcontents.setCellData(rp, "stlAcctNm", returnValue.stlAcctNm);
    ds_slipcontents.setCellData(rp, "stlAmt", returnValue.stlAmt);
    ds_slipcontents.setCellData(rp, "stlRamt", returnValue.stlRamt);
    ds_slipcontents.setCellData(rp, "stlAmtFcrc", returnValue.stlAmtFcrc);
    ds_slipcontents.setCellData(rp, "stlRamtFcrc", returnValue.stlRamtFcrc);
    ds_slipcontents.setCellData(rp, "stlCrcCd", returnValue.stlCrcCd);
    ds_slipcontents.setCellData(rp, "stlExchRt", returnValue.stlExchRt);
    if (typeof returnValue.stlOutbrNo == "undefined") {
      ed_refNo.setValue("");
    } else {
      ed_refNo.setValue(returnValue.stlOutbrNo);
    }
  }
};
