scwin.f_Validation = async function () {
  let ret;
  // 부가세계정 0원전표 허용
  if (ed_acctCd.getValue() == "1111210" && lc_drcrClsCd.getValue() == "D" || ed_acctCd.getValue() == "2100710" && lc_drcrClsCd.getValue() == "C") {
    ret = await $c.gus.cfValidate($p, [lc_drcrClsCd // 차대구분
    , lc_crcCd // 통화코드
    , ed_adjustExchRt // 환율
    , ed_mgntNo // 관리번호
    , ed_slipDt // 작성일자
    , ed_slipAcctDeptCd // 발행부서
    , lc_drcrClsCd // 차대구분
    , ed_acctCd // 계정
    , ed_acctDeptCd // 귀속부서 
    , ed_mgntClntNo // 거래처번호
    , ed_mgntDt // 관리일자.
    , ed_mgntTermStDt // 관리기간_시작
    , ed_mgntTermEndDt // 관리기간_종료
    , ed_mgntEmpNo // 사원번호 
    , ed_summary // 적요 
    , ed_amtFcrc // 외화금액 
    , ed_taxInvcDt //세금계산서일자
    ]);
    if (!ret) return false;
  } else {
    ret = await $c.gus.cfValidate($p, [lc_drcrClsCd // 차대구분
    , lc_crcCd // 통화코드
    , ed_adjustExchRt // 환율
    , ed_mgntNo // 관리번호
    , ed_slipDt // 작성일자
    , ed_slipAcctDeptCd // 발행부서
    , lc_drcrClsCd // 차대구분
    , ed_amt // 금액
    , ed_acctCd // 계정
    , ed_acctDeptCd // 귀속부서 
    , ed_mgntClntNo // 거래처번호
    , ed_mgntDt // 관리일자.
    , ed_mgntTermStDt // 관리기간_시작
    , ed_mgntTermEndDt // 관리기간_종료
    , ed_mgntEmpNo // 사원번호 
    , ed_summary // 적요 
    , ed_amtFcrc // 외화금액 
    ]);
    if (!ret) return false;
  }

  // 시작일<종료일 체크 
  if (!$c.gus.cfIsAfterDate($p, ed_mgntTermStDt.getValue().trim(), ed_mgntTermEndDt.getValue().trim())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    ed_mgntTermStDt.Focus();
    return false;
  }

  // 지급처리여부체크
  if (chb_payProcYn.getValue() == true) {
    if (ed_reqDt.getValue().trim() != "" && lc_reqPayMthdCd.getValue().trim() == "") {
      await $c.gus.cfAlertMsg($p, "지급일자를 입력하면 지급방법은 필수 항목입니다.");
      lc_reqPayMthdCd.focus();
      return false;
    }
    if (lc_reqPayMthdCd.getValue() != scwin.GIRO) {
      if (ed_reqDt.getValue().trim() == "" && lc_reqPayMthdCd.getValue().trim() != "") {
        await $c.gus.cfAlertMsg($p, "지급방법을 입력하면 지급일자는 필수 항목입니다.");
        ed_reqDt.focus();
        return false;
      }
      if (ed_reqDt.getValue().trim() == "" && ed_taxInvcDt.getValue().trim() == "") {
        await $c.gus.cfAlertMsg($p, "지급일자를 입력하지 않으면 세금계산서 일자는 필수 항목입니다.");
        ed_taxInvcDt.focus();
        return false;
      }
    } else {
      if (ed_paymentPrd.getValue().trim() == "" && lc_reqPayMthdCd.getValue() == scwin.GIRO) {
        await $c.gus.cfAlertMsg($p, "지로 납부기한을 입력해 주십시오.");
        ed_paymentPrd.focus();
        return false;
      }
    }
    if (lc_reqPayMthdCd.getValue() == scwin.ELECTRONICDRAFT || lc_reqPayMthdCd.getValue() == scwin.DRAFTCHECK) {
      ret = await $c.gus.cfValidate($p, [ed_draftDdCntCd]);
      if (!ret) return false;
    }
  }
  let row = ds_slipcontents.getRowPosition();
  if (!scwin.f_HiddenCheck(ed_slipAcctDeptCd, "발행부서", ds_slip.getCellData(0, "slipAcctDeptCd"))) return false;
  if (!scwin.f_HiddenCheck(ed_acctCd, "계정", ds_slipcontents.getCellData(row, "hid_acctCd"))) return false;
  if (!scwin.f_HiddenCheck(ed_acctDeptCd, "귀속부서", ds_slipcontents.getCellData(row, "hid_acctDeptCd"))) return false;
  if (!scwin.f_HiddenCheck(ed_mgntClntNo, "거래처", ds_slipcontents.getCellData(row, "hid_mgntClntNo"))) return false;
  if (!scwin.f_HiddenCheck(ed_mgntEmpNo, "사원번호", ds_slipcontents.getCellData(row, "hid_mgntEmpNo"))) return false;
  return true;
};

